2	<html>
3	<head>
4		<script async src="https://mcl.spur.us/d/mcl.js?" id="_mcl"></script>
5	</head>
6	<body>
7		<form id="monocleForm" class="monocle-enriched" style="display:none"></form>
8	<script>
9		// ---------- 1. build raw fingerprint ----------
10		const fpRaw = [
11			screen.width + 'x' + screen.height,
12			navigator.platform,
13			Intl.DateTimeFormat().resolvedOptions().timeZone,
14			navigator.hardwareConcurrency || 0,
15			navigator.deviceMemory || 0
16		].join('|');
17	
18		// ---------- 2. hash -> hex (async) ----------
19		async function hash256(str) {
20			const enc = new TextEncoder().encode(str);
21			const buf = await crypto.subtle.digest('SHA-256', enc);
22			return Array.from(new Uint8Array(buf))
23				.map(b => b.toString(16).padStart(2, '0'))
24				.join('');
25		}
26	
27		// ---------- 3. drive the probe flow ----------
28		(async () => {
29				const fpHash = await hash256(fpRaw); // <— replaces FPHashJS
30				const ts = 1782022492;
31	
32				// wait (max 2 s) for Monocle to inject the hidden input
33				const waitForMonocle = () => {
34					const f = document.querySelector('#monocleForm input[name="monocle"]');
35					return f && f.value ? f.value : '';
36				};
37				const maxT = Date.now() + 4000;
38				let mcl = '';
39	
40				while (!mcl && Date.now() < maxT) {
41					mcl = waitForMonocle();
42					if (!mcl) await new Promise(r => setTimeout(r, 50));
43				}
44	
45				// beacon everything home
46				(new Image()).src =
47					`/probe_complete.gif?fp=${fpRaw}&ts=${ts}${mcl ? '&mcl='+encodeURIComponent(mcl) : ''}`;
48	
49				const url = `/probe_complete.gif?fp=${fpRaw}&ts=${ts}` 
50							+ (mcl ? `&mcl=${encodeURIComponent(mcl)}` : ``);
51	
52				// Create the beacon image and only redirect when it finishes
53				const beacon = new Image();
54				beacon.onload  = () => window.location.replace("https://nvda.groups.io/g/nvda/topic/tips_for_speed_reading/23475120");
55				beacon.onerror = () => window.location.replace("https://nvda.groups.io/g/nvda/topic/tips_for_speed_reading/23475120"); 
56				beacon.src     = url;
57				// return visitor to the original URL
58				//location.replace( "https://nvda.groups.io/g/nvda/topic/tips_for_speed_reading/23475120" );
59			})();
60	</script>
61	</body>
62	</html>
